export const MODE_ORDER=['offseason','inseason','onice','office'];
export const TOTAL_WEEKS=32;
export const blockForWeek=(w)=>Math.ceil(w/4);
export const phaseForWeek=(w)=>(w<=8?'Off-Season':'In-Season');
export function resolveContent(mode,week){
  const [lo,hi]=mode.range; const cw=Math.min(Math.max(week,lo),hi);
  const key=mode.weekly?cw:blockForWeek(cw);
  let content=mode.blocks[key];
  if(!content){const keys=Object.keys(mode.blocks).map(Number).sort((a,z)=>a-z);content=mode.blocks[keys[0]];}
  return {content,inRange:week>=lo&&week<=hi,blockNum:blockForWeek(cw)};
}
export const FIELD_META={weight:{label:'Wt',type:'number',ph:'lb'},reps:{label:'Reps',type:'number',ph:'reps'},time:{label:'Time',type:'text',ph:'sec'},notes:{label:'Notes',type:'text',ph:'notes…'}};
export function targetReps(target){const m=/x\s*(\d+)/.exec(target||'');return m?parseInt(m[1],10):null;}
